$ErrorActionPreference = 'Stop'

function Write-KlevaProgress {
  param([int]$Percent)

  if ($Percent -lt 0) { $Percent = 0 }
  if ($Percent -gt 100) { $Percent = 100 }
  Write-Output ("KLEVADEPLOY_PROGRESS:{0}" -f $Percent)
}

function Get-OfficeEnvValue {
  param(
    [string]$Name,
    [string]$Default = ''
  )

  $value = [Environment]::GetEnvironmentVariable($Name)
  if ([string]::IsNullOrWhiteSpace($value)) { return $Default }
  return $value.Trim()
}

function ConvertTo-KlevaBool {
  param(
    [string]$Value,
    [bool]$Default = $false
  )

  if ([string]::IsNullOrWhiteSpace($Value)) { return $Default }

  switch -Regex ($Value.Trim().ToLowerInvariant()) {
    '^(1|true|yes|y|on)$' { return $true }
    '^(0|false|no|n|off)$' { return $false }
    default { return $Default }
  }
}

function ConvertTo-XmlAttributeValue {
  param([string]$Value)

  if ($null -eq $Value) { return '' }
  return [System.Security.SecurityElement]::Escape($Value)
}

function Get-OfficePaths {
  $dataDir = $env:KLEVADEPLOY_DATA_DIR
  if ([string]::IsNullOrWhiteSpace($dataDir)) { throw 'KLEVADEPLOY_DATA_DIR missing' }

  $rootDir = Join-Path $dataDir 'installers\office365-setup'
  $sourceDir = Join-Path $dataDir 'installers\office365-cache'
  $configDir = Join-Path $dataDir 'installers\office365-config'
  $logsDir = Join-Path $dataDir 'logs\office365'

  return @{
    DataDir = $dataDir
    RootDir = $rootDir
    SetupPath = (Join-Path $rootDir 'setup.exe')
    SourceDir = $sourceDir
    ConfigDir = $configDir
    ConfigPath = (Join-Path $configDir 'office365.generated.xml')
    LogsDir = $logsDir
  }
}

function New-OfficeDirectories {
  param($Paths)

  foreach ($path in @($Paths.RootDir, $Paths.SourceDir, $Paths.ConfigDir, $Paths.LogsDir)) {
    New-Item -ItemType Directory -Force -Path $path | Out-Null
  }
}

function Get-OfficeExcludedAppsXml {
  param([string]$RawValue)

  $ids = New-Object 'System.Collections.Generic.List[string]'
  $seen = New-Object 'System.Collections.Generic.HashSet[string]' ([System.StringComparer]::OrdinalIgnoreCase)

  $raw = $RawValue
  if ($null -eq $raw) { $raw = '' }

  foreach ($token in $raw -split '[,;]') {
    $value = $token
    if ($null -eq $value) { $value = '' }
    $value = $value.Trim()
    if ([string]::IsNullOrWhiteSpace($value)) { continue }
    if ($seen.Add($value)) {
      $ids.Add($value)
    }
  }

  if ($ids.Count -eq 0) { return @() }

  return @($ids | ForEach-Object { "      <ExcludeApp ID=""$(ConvertTo-XmlAttributeValue $_)"" />" })
}

function New-OfficeConfigurationXml {
  param(
    [string]$SourcePath,
    [string]$LogsPath
  )

  $edition = Get-OfficeEnvValue -Name 'KLEVADEPLOY_OFFICE_EDITION' -Default '64'
  if ($edition -notin @('32', '64')) { $edition = '64' }

  $productId = Get-OfficeEnvValue -Name 'KLEVADEPLOY_OFFICE_PRODUCT' -Default 'O365ProPlusRetail'
  $channel = Get-OfficeEnvValue -Name 'KLEVADEPLOY_OFFICE_CHANNEL' -Default 'MonthlyEnterprise'
  $language = Get-OfficeEnvValue -Name 'KLEVADEPLOY_OFFICE_LANGUAGE' -Default 'en-us'
  $excludeApps = Get-OfficeEnvValue -Name 'KLEVADEPLOY_OFFICE_EXCLUDE_APPS' -Default ''

  $removeMsi = ConvertTo-KlevaBool -Value (Get-OfficeEnvValue -Name 'KLEVADEPLOY_OFFICE_REMOVE_MSI' -Default 'true') -Default $true
  $sharedComputer = ConvertTo-KlevaBool -Value (Get-OfficeEnvValue -Name 'KLEVADEPLOY_OFFICE_SHARED_COMPUTER_ACTIVATION' -Default 'false') -Default $false
  $forceAppShutdown = ConvertTo-KlevaBool -Value (Get-OfficeEnvValue -Name 'KLEVADEPLOY_OFFICE_FORCE_APP_SHUTDOWN' -Default 'true') -Default $true

  $lines = New-Object 'System.Collections.Generic.List[string]'
  $lines.Add('<Configuration>')
  $lines.Add(("  <Add OfficeClientEdition=""{0}"" Channel=""{1}"" SourcePath=""{2}"">" -f `
      (ConvertTo-XmlAttributeValue $edition), `
      (ConvertTo-XmlAttributeValue $channel), `
      (ConvertTo-XmlAttributeValue $SourcePath)))
  $lines.Add(("    <Product ID=""{0}"">" -f (ConvertTo-XmlAttributeValue $productId)))
  $lines.Add(("      <Language ID=""{0}"" />" -f (ConvertTo-XmlAttributeValue $language)))

  foreach ($line in (Get-OfficeExcludedAppsXml -RawValue $excludeApps)) {
    $lines.Add($line)
  }

  $lines.Add('    </Product>')
  $lines.Add('  </Add>')

  if ($removeMsi) {
    $lines.Add('  <RemoveMSI />')
  }

  $lines.Add('  <Updates Enabled="TRUE" />')
  $lines.Add('  <Display Level="None" AcceptEULA="TRUE" />')
  $lines.Add(("  <Logging Level=""Standard"" Path=""{0}"" />" -f (ConvertTo-XmlAttributeValue $LogsPath)))

  if ($sharedComputer) {
    $lines.Add('  <Property Name="SharedComputerLicensing" Value="1" />')
  }

  if ($forceAppShutdown) {
    $lines.Add('  <Property Name="FORCEAPPSHUTDOWN" Value="TRUE" />')
  }

  $lines.Add('</Configuration>')

  return ($lines -join "`r`n")
}

function Write-OfficeConfigurationFile {
  $paths = Get-OfficePaths
  New-OfficeDirectories -Paths $paths

  $xml = New-OfficeConfigurationXml -SourcePath $paths.SourceDir -LogsPath $paths.LogsDir
  Set-Content -Path $paths.ConfigPath -Value $xml -Encoding UTF8
  return $paths.ConfigPath
}

function Test-OfficeSourceCachePresent {
  param([string]$SourceDir)

  if ([string]::IsNullOrWhiteSpace($SourceDir)) { return $false }
  if (!(Test-Path $SourceDir)) { return $false }

  $officeDataDir = Join-Path $SourceDir 'Office\Data'
  if (Test-Path $officeDataDir) {
    $dataFile = Get-ChildItem -Path $officeDataDir -Recurse -File -ErrorAction SilentlyContinue | Select-Object -First 1
    return $null -ne $dataFile
  }

  $fallbackFile = Get-ChildItem -Path $SourceDir -Recurse -File -ErrorAction SilentlyContinue | Select-Object -First 1
  return $null -ne $fallbackFile
}

function Invoke-OfficeSetup {
  param([string]$ArgumentLine)

  $paths = Get-OfficePaths
  if (!(Test-Path $paths.SetupPath)) {
    throw ('Office setup.exe not found: ' + $paths.SetupPath)
  }

  $process = Start-Process -FilePath $paths.SetupPath -ArgumentList $ArgumentLine -Wait -PassThru -WindowStyle Hidden
  return $process.ExitCode
}

$paths = Get-OfficePaths
New-OfficeDirectories -Paths $paths

Write-KlevaProgress 5
$configPath = Write-OfficeConfigurationFile
$hadCache = Test-OfficeSourceCachePresent -SourceDir $paths.SourceDir

if ($hadCache) {
  Write-Output 'Office: local source cache found. Checking for source updates.'
} else {
  Write-Output 'Office: local source cache not found. Downloading installation files.'
}

Write-KlevaProgress 20
$exitCode = 0

try {
  $exitCode = Invoke-OfficeSetup -ArgumentLine "/download `"$configPath`""
} catch {
  if ($hadCache) {
    Write-Warning ('Office: source refresh failed, using cached files instead. ' + $_.Exception.Message)
    Write-KlevaProgress 100
    exit 0
  }

  throw
}

if ($exitCode -eq 0) {
  if (!(Test-OfficeSourceCachePresent -SourceDir $paths.SourceDir)) {
    throw ('Office source cache was not created: ' + $paths.SourceDir)
  }

  Write-Output 'Office: source cache is ready.'
  Write-KlevaProgress 100
  exit 0
}

if ($hadCache) {
  Write-Warning ('Office: source refresh returned exit code ' + $exitCode + '. Continuing with cached source files.')
  Write-KlevaProgress 100
  exit 0
}

exit $exitCode

